int maxDegree(const std::vector<int> &A, size_t N)
{
    // Highest degree seen so far
    int max_deg = 0;

    // Parallel loop over rows.  Reduction keeps the maximum degree
    // across all threads.
    #pragma omp parallel for reduction(max : max_deg) schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i)
