/* Count the number of Cartesian points in each quadrant.
   points – list of Point objects
   bins – output array: [Q0, Q1, Q2, Q3]
*/
inline void countQuadrants(std::vector<Point> const& points,
                           std::array<std::size_t, 4>& bins) {
    // Local per‑thread accumulators to avoid synchronization during the loop
    const std::size_t nthreads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 4>> local_bins(nthreads);
    #pragma omp parallel
