        auto& tb = local_bins[tid];
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < points.size(); ++i) {
            const auto& p = points[i];
            if (p.x >= 0.0) {
                tb[p.y >= 0.0 ? 0 : 3] += 1;
            } else {
                tb[p.y >= 0.0 ? 1 : 2] += 1;
            }
        }
    }
    // Reduce per‑thread counts into the final result
    bins.fill(0);
    for (const auto& t : local_bins) {
        for (std::size_t q = 0; q < 4; ++q)
            bins[q] += t[q];
    }
