#pragma once
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

/*
 * In the vector `x` negate the odd values and divide the even values by 2.
 * Example:
 *
 *   input: [16, 11, 12, 14, 1, 0, 5]
 *   output: [8, -11, 6, 7, -1, 0, -5]
 */
inline void negateOddsAndHalveEvens(std::vector<int> &x)
{
    const std::size_t n = x.size();

    /* Use a raw pointer for fast indexing and enforce a natural chunking
     * that keeps the memory traffic to a minimum on a typical x86-64
     * SMP.  gcc - O2 + -fopenmp will vectorise the body automatically
     * when the loop body contains only simple integer operations.  */
    int *restrict ptr = x.data();

    /* Parallelize the loop with static scheduling to keep work
     * evenly distributed among the available 8 threads.  */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i)
    {
        const int v = ptr[i];
        if ((v & 1) == 0)          // even
            ptr[i] = v >> 1;        // divide by 2 using a right shift
        else
            ptr[i] = -v;            // negate odd values
    }
}
