// Optimised shortestPathLength implementation
#pragma once
#include <vector>
#include <limits>

int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) {
    // A is stored in row-major. Use a flat array for the queue.
    std::vector<char> visited(N, 0);            // 1 byte per vertex is enough
    std::vector<int>  q(N);                     // max size N
    size_t q_head = 0, q_tail = 0;

    visited[source] = 1;
    q[q_tail++] = source * N;                   // store offset to source row
    int level = 0;

    while (q_head < q_tail) {
        size_t level_end = q_tail;              // all vertices at current level
        while (q_head < level_end) {
            int offset = q[q_head++];
            int current = offset / N;
            if (current == dest) return level;

            // Scan the current row for neighbours
            const int row_start = offset;      // offset already points to first element
            for (int i = 0; i < N; ++i) {
                if (A[row_start + i] && !visited[i]) {
                    visited[i] = 1;
                    q[q_tail++] = i * N;        // store new row offset
                }
            }
        }
        ++level;                                // next BFS level
    }
    return std::numeric_limits<int>::max();
}
