#pragma once
#include <vector>
#include <array>
#include <cstddef>
#include <cstdint>
#include <omp.h>

/*
 * Count the number of pixels in `image` with each grayscale intensity (0‑255)
 * and store the results in `bins`.  The original code was a simple
 * sequential loop.  This implementation uses OpenMP to parallelise the
 * histogram calculation, a per‑thread local histogram to avoid contention,
 * and a final reduction step to combine the partial histograms.
 * The algorithm is fully deterministic and produces exactly the same
 * bin counts as the sequential version.
 */
void pixelCounts(std::vector<int> const &image, std::array<size_t, 256> &bins) {
    // Number of threads to spawn.  If the runtime hasn't set a value
    // (default), we use 8 as suggested by the environment.
    int nthreads = omp_get_max_threads();
    if (nthreads == 0) nthreads = 8;

    // Each thread will compute a local histogram.
    std::vector<std::array<size_t, 256>> localBins(nthreads);
    for (auto &b : localBins) b.fill(0);

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto &local = localBins[tid];

        // Upper bound for this thread.
        size_t chunk_start, chunk_end;
        #pragma omp for schedule(static)
        for (size_t i = 0; i < image.size(); ++i) {
            local[static_cast<uint8_t>(image[i])]++;
        }
    }

    // Reduce all local histograms into the output array.
    bins.fill(0);
    for (int t = 0; t < nthreads; ++t) {
        const auto &local = localBins[t];
        for (int k = 0; k < 256; ++k) {
            bins[k] += local[k];
        }
    }
}
