/*
   Count how many strings in `s` begin with each lowercase alphabet letter
   and store the counts in `bins`.
   The function is fully parallelized with OpenMP and uses a cache‑friendly
   approach to minimise contention and memory stalls.
*/
inline void firstLetterCounts(const std::vector<std::string> &s,
                              std::array<size_t, 26> &bins) {

    // Initialize bins to zero (total cost: negligible compared to work size)
    bins.fill(0);

    // Number of threads is decided by the OpenMP runtime.
    // Each thread keeps its own local bins array to avoid atomic
    // operations or data races.
    const size_t n = s.size();
    if (n == 0) return;

    const size_t num_threads = omp_get_max_threads();
    // Allocate one array per thread; each will be 26*sizeof(size_t)
    std::vector<std::array<size_t, 26>> local_bins(num_threads);
    for (auto &a : local_bins) a.fill(0);

    // Parallel loop with schedule(static) for better cache locality
    #pragma omp parallel for schedule(static, n / num_threads + 1)
    for (size_t i = 0; i < n; ++i) {
        const std::string &str = s[i];
        // Guard against empty strings (original code did not handle this,
        // but we preserve behaviour by skipping them)
        if (!str.empty()) {
            const char c = str[0];
            const int idx = c - 'a';
            // Assuming input is guaranteed to be lower‑case alphabetic.
            local_bins[omp_get_thread_num()][idx] += 1;
        }
    }

    // Reduce thread‑local bins into the final result.
    for (size_t t = 0; t < num_threads; ++t) {
        for (int j = 0; j < 26; ++j) {
            bins[j] += local_bins[t][j];
        }
    }
}
