struct Element {
    size_t index;
    double value;
};

inline void sparseAxpy(double alpha,
                       const std::vector<Element> &x,
                       const std::vector<Element> &y,
                       std::vector<double> &z)
{
    /* 
     * Addition of independent sparse vectors is commutative, so we can
     * update z in parallel for each input vector. Overlapping indices
     * simply receive both contributions.
     */
    #pragma omp parallel for schedule(static) 
    for (size_t i = 0; i < x.size(); ++i)
        z[x[i].index] += alpha * x[i].value;

    #pragma omp parallel for schedule(static) 
    for (size_t i = 0; i < y.size(); ++i)
        z[y[i].index] += y[i].value;
}
