/*
 * Compute the reverse prefix sum of the vector x into output.
 * The function guarantees that output[i] = sum_{j=i}^{n-1} x[j].
 * This implementation avoids extra allocations and runs in a single
 * pass, which is optimal on a modern x86‑64 CPU.
 */
void reversePrefixSum(std::vector<int> const& x, std::vector<int> &output) {
    const std::size_t n = x.size();
    output.resize(n);                       // ensure correct size
    long long acc = 0;                      // 64‑bit accumulator to avoid overflow
