#pragma once
#include <vector>
#include <algorithm>
#include <cstdint>

// -----------------------------------------------------------------------------
// FAST ITERATIVE DFS
// -----------------------------------------------------------------------------
inline void dfs_iter(std::vector<int> const& A, int start,
                     size_t N, std::vector<uint8_t>& visited,
                     int& count)
{
    // Simple manual stack (array) – N is known at runtime but small enough
    // for stack allocation in most cases; if N is huge we fall back to
    // dynamic allocation.
    int *stack = nullptr;
    bool useDynamic = N > 128000; // arbitrary threshold to avoid large stack
    if (!useDynamic) {
        // Allocate on the frame
        int stackLocal[128000];
        stack = stackLocal;
    } else {
        stack = new int[N];
    }

    int sp = 0;
    stack[sp++] = start;

    while (sp) {
        int v = stack[--sp];
        if (visited[v]) continue;
        visited[v] = 1;
        ++count;

        // Scan row v for neighbors
        const int *row = &A[v * N];
        for (int u = 0; u < N; ++u) {
            if (row[u] && !visited[u]) {
                stack[sp++] = u;
            }
        }
    }

    if (useDynamic) delete[] stack;
}

// -----------------------------------------------------------------------------
// Main entry
// -----------------------------------------------------------------------------
int largestComponent(std::vector<int> const& A, size_t N)
{
    std::vector<uint8_t> visited(N, 0);
    int maxCount = 0;

    for (int i = 0; i < static_cast<int>(N); ++i) {
        if (!visited[i]) {
            int count = 0;
            dfs_iter(A, i, N, visited, count);
            if (count > maxCount) maxCount = count;
        }
    }
    return maxCount;
}
