 *   output[i] = (input[i-1] + input[i] + input[i+1]) / 3,
 * with out‑of‑bounds neighbors treated as 0.
 */
inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output)
{
    const size_t n = input.size();
    if (n == 0) return;

    const double inv3 = 1.0 / 3.0;

    // Pointers for faster random access
    const double *in = input.data();
    double       *out = output.data();

    // Parallel loop – work shares across threads
    #pragma omp parallel for schedule(static)
    for (long long i = 0; i < static_cast<long long>(n); ++i) {
        double sum = in[i];                     // center
        if (i > 0)     sum += in[i - 1];         // left
        if (i + 1 < static_cast<long long>(n))
            sum += in[i + 1];                   // right
        out[i] = sum * inv3;                    // multiply by 1/3
    }
}
