struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Compute y = alpha*A*x + beta*y
 * where A is stored in COO format
 */
static inline void spmv(double          alpha,
                        std::vector<COOElement> const& A,
                        std::vector<double> const&    x,
                        double          beta,
                        std::vector<double>&         y,
                        size_t          M,
                        size_t          N) {
    /* Scale y by beta (parallel). */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        y[i] *= beta;
    }

    /* Gather the contributions in thread‑local buffers.
     * Each thread owns a small array of size M that it updates
     * without contention. At the end we merge the thread
     * buffers into the final result. */
    const int nthreads = omp_get_max_threads();
    std::vector<std::vector<double>> local(nthreads, std::vector<double>(M, 0.0));

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();

        /* Parallel loop over the COO entries. */
        #pragma omp for schedule(static)
        for (std::size_t idx = 0; idx < A.size(); ++idx) {
            const auto& e = A[idx];
            if (e.row < M && e.column < N) {
                local[tid][e.row] += alpha * e.value * x[e.column];
            }
        }
    }

    /* Accumulate the local partial sums into the final vector y. */
    for (int t = 0; t < nthreads; ++t) {
        for (std::size_t i = 0; i < M; ++i) {
            y[i] += local[t][i];
        }
    }
}
