49_sparse_la_sparse_lu_decomp:
```cpp
#pragma once
#include <vector>
#include <omp.h>
#include <cstddef>

struct COOElement {
    std::size_t row, column;
    double value;
};

/*
 * Same behavioral signature as the reference implementation.
 *
 * The routine constructs dense matrices L and U in row-major order.
 * The algorithm is a straightforward Doolittle LU decomposition.
 *
 * Parallelism: each outer‑loop iteration (row) is independent once former
 * rows have been computed, so we safely parallelise the loop over `i`
 * with OpenMP. We use `reduction` only for the temporary sum
 * accumulation to avoid extra branches.
 */
inline void luFactorize(const std::vector<COOElement>& A,
                        std::vector<double>& L,
                        std::vector<double>& U,
                        std::size_t N)
{
    /* Allocate dense matrix in a 1‑D array for cache friendliness */
    std::vector<double> fullA(N * N, 0.0);
    for (const auto& e : A)
        fullA[e.row * N + e.column] = e.value;

    /* Ensure output vectors are sized correctly */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* Doolittle LU decomposition (row‑by‑row) */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        /* Compute U[i][j] for j >= i */
        for (std::size_t j = i; j < N; ++j) {
            double sum = fullA[i * N + j];
            for (std::size_t k = 0; k < i; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = sum;
        }

        /* Compute L[i][j] for j < i */
        for (std::size_t j = 0; j < i; ++j) {
            double sum = fullA[i * N + j];
            for (std::size_t k = 0; k < j; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            L[i * N + j] = sum / U[j * N + j];
        }

        /* Diagonal of L is 1 */
        L[i * N + i] = 1.0;
    }
}
