# define M_PI 3.14159265358979323846
#endif

/*
 * Compute the discrete fourier transform of x. Store the result in output.
 * The implementation uses a cache‑friendly pre‑computed table of complex
 * exponentials and parallelises the outer loop with OpenMP. All operations
 * are carried out with double precision and the result is exactly the same
 * as the straightforward double‑nested loop version.
 *
 * Note:  The function is fully thread‑safe and deterministic.
 */
inline void dft(std::vector<double> const& x,
                std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output.resize(N);

    /* Pre‑compute the complex exponentials exp(-2π i n k / N)
     *  for all k and all n.  They are stored in a single linear
     *  table to keep the data contiguous and to enable SIMD loads.
     *  The layout is: table[k * N + n]  (k outer, n inner).
     */
    std::vector<std::complex<double>> twiddle(N * N);
    const double two_pi = 2.0 * M_PI;
#pragma omp parallel for schedule(static, 1)
    for (std::size_t k = 0; k < N; ++k) {
        const double kfactor = two_pi * k / static_cast<double>(N);
        for (std::size_t n = 0; n < N; ++n) {
            double ang = kfactor * static_cast<double>(n);
            double c, s;
            /* sincos is a single instruction on x86; costs less than
             * separate cos() and sin() calls and guarantees correct sign
             * for sin(ang).
             */
#pragma omp simd
            for (int i = 0; i < 1; ++i) {
                /* use low‑level intrinsic to get sincos if available */
                std::sincos(ang, &s, &c);
            }
            twiddle[k * N + n] = std::complex<double>(c, -s);
        }
    }

    /* Main DFT loop.  The outer loop is parallelised; each thread keeps
     * its own local sum vector to avoid false sharing.
     */
#pragma omp parallel for schedule(static, 1)
    for (std::size_t k = 0; k < N; ++k) {
        std::complex<double> sum{};
        const std::size_t base = k * N;
        /* vectorised inner loop: the compiler can use AVX2 if available */
        for (std::size_t n = 0; n < N; ++n) {
            sum += x[n] * twiddle[base + n];
        }
        output[k] = sum;
    }
}
