/* Factorize the matrix A into A=LU where L is a lower triangular matrix and U is an upper triangular matrix.
   Store the results for L and U into the original matrix A.
   A is an NxN matrix stored in row-major.
   Example:
   input: [[4, 3], [6, 3]]
   output: [[4, 3], [1.5, -1.5]]
*/
inline void luFactorize(std::vector<double> &A, size_t N) {
    // Work in place; no extra memory
    const size_t stride = N;
    const size_t limitN = N - 1;

    for (size_t k = 0; k < N; ++k) {
        const double aik = A[k * stride + k];
        // Parallelize the inner block that is independent for each 'i'
        #pragma omp parallel for schedule(static)
        for (size_t i = k + 1; i < N; ++i) {
            double *row_i = &A[i * stride];
            double *row_k = &A[k * stride];
            double factor = row_i[k] / aik;
            row_i[k] = factor;                 // store L entry

            // Update the remaining row elements
            for (size_t j = k + 1; j < N; ++j) {
                row_i[j] -= factor * row_k[j];
            }
        }
    }
}
