//=============================================================================
// cellsXOR: For every cell of an NxN grid, set the output cell to 1 iff
//            exactly one of the four orthogonal neighbours (up, down, left,
//            right) in the input grid is a 1. Neighbourhood is considered in
//            the input only; the current cell's own value is ignored.
//
// The function is fully parallelised with OpenMP and uses simple pointer
// arithmetic for maximum cache efficiency.
//=============================================================================
void cellsXOR(std::vector<int> const& input,
              std::vector<int>& output,
              size_t N) noexcept
{
    // guard against empty grid
    if (N == 0) return;

    const int* in  = input.data();
    int*      out = output.data();
    const size_t stride = N;

    // Parallel over all rows. Inner loop over columns is kept inside the
    // parallel for in order to avoid thread idle time on very small N.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t up   = (i > 0)     ? i - 1 : SIZE_MAX;
        const size_t down = (i + 1 < N) ? i + 1 : SIZE_MAX;

        for (size_t j = 0; j < N; ++j)
        {
            int cnt = 0;

            // Ensure that we only read valid indices.
            if (up  != SIZE_MAX && in[up * stride + j]   == 1) ++cnt;
            if (down != SIZE_MAX && in[down * stride + j] == 1) ++cnt;
            if (j > 0           && in[i * stride + j - 1] == 1) ++cnt;
            if (j + 1 < N       && in[i * stride + j + 1] == 1) ++cnt;

            out[i * stride + j] = (cnt == 1) ? 1 : 0;
        }
    }
}
