/*
   Multiply the matrix A by the vector x. Store the results in the vector y.
   A is an MxN matrix stored in row-major, x has N elements, and y has M elements.
   Example:
   input: A=[[1, -1, 2], [0, -3, 1]] x=[2, 1, 0]
   output: y=[1, -3]
*/
inline void gemv(const std::vector<double> &A, const std::vector<double> &x,
                 std::vector<double> &y, std::size_t M, std::size_t N) {
    const double *const a = A.data();
    const double *const v = x.data();
    double *const r = y.data();

    const std::size_t block = 64; // row block size for cache locality

    #pragma omp parallel for schedule(static)
    for (std::size_t bi = 0; bi < M; bi += block) {
        const std::size_t i_end = std::min(bi + block, M);
        for (std::size_t i = bi; i < i_end; ++i) {
            const double *ai = a + i * N;
            double sum = 0.0;
            std::size_t j = 0;
            // vectorised inner loop
            for (; j + 3 < N; j += 4) {
                sum += ai[j]   * v[j];
                sum += ai[j+1] * v[j+1];
                sum += ai[j+2] * v[j+2];
                sum += ai[j+3] * v[j+3];
            }
            for (; j < N; ++j) sum += ai[j] * v[j];
            r[i] = sum;
        }
    }
}
