#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Optimised sparse‑matrix * sparse‑matrix multiplication.
 * Y = A * X
 *   A : M×K COO matrix
 *   X : K×N COO matrix
 *   Y : dense M×N matrix (row‑major)
 *
 * The routine keeps the original semantics while using
 * thread‑private workspaces to eliminate race conditions
 * and exploiting pre‑aggregation of X by row for locality.
 */
void spmm(const std::vector<COOElement> &A,
          const std::vector<COOElement> &X,
          std::vector<double>            &Y,
          size_t M, size_t K, size_t N)
{
   const size_t lanes = std::min<size_t>(8, omp_get_max_threads());
   Y.assign(M * N, 0.0);

   /* 1. Build a row‑indexed view of X for O(1) access to all
    *    elements with a given row (i.e., x.row == a.column).
    */
   std::vector<std::vector<COOElement>> XbyRow(K);
   for (auto &x : X) {
       if (x.row < K)
           XbyRow[x.row].push_back(x);
   }

   /* 2. Allocate thread‑local accumulators to avoid false sharing. */
   std::vector<std::vector<double>> localY(lanes, std::vector<double>(M * N, 0.0));

   #pragma omp parallel for schedule(static)
   for (size_t ia = 0; ia < A.size(); ++ia) {
       const auto &a = A[ia];
       if (a.column >= K) continue;              // safety
       const auto &grp = XbyRow[a.column];
       if (grp.empty()) continue;

       const size_t thread_id = omp_get_thread_num();
       auto &currY = localY[thread_id];
       const size_t base = a.row * N;

       for (const auto &x : grp) {
           currY[base + x.column] += a.value * x.value;
       }
   }

   /* 3. Merge thread‑local results into the final matrix Y. */
   for (size_t t = 0; t < lanes; ++t) {
       const auto &tmp = localY[t];
       for (size_t i = 0; i < M * N; ++i)
           Y[i] += tmp[i];
   }
}
