#pragma once
#include <vector>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
inline void solveLinearSystem(std::vector<double> const& A,
                              std::vector<double> const& b,
                              std::vector<double> &x,
                              size_t N)
{
    // Working copies (use raw pointers for speed)
    std::vector<double> A_copy(A);
    std::vector<double> b_copy(b);

    // Gaussian elimination with partial pivoting (no row swaps here for simplicity)
    for (size_t i = 0; i < N - 1; ++i)
    {
        double pivot = A_copy[i * N + i];
        if (pivot == 0.0) return;                         // singular matrix

        // Parallelise elimination of rows below the pivot
        #pragma omp parallel for schedule(static,128) collapse(2)
        for (size_t j = i + 1; j < N; ++j)
        {
            double factor = A_copy[j * N + i] / pivot;
            for (size_t k = i; k < N; ++k)
                A_copy[j * N + k] -= factor * A_copy[i * N + k];
            b_copy[j] -= factor * b_copy[i];
        }
    }

    // Back‑substitution (single thread – very thin loop)
    for (int i = static_cast<int>(N) - 1; i >= 0; --i)
    {
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j)
            sum += A_copy[i * N + j] * x[j];
        x[i] = (b_copy[i] - sum) / A_copy[i * N + i];
    }
}
