}

// Computes the perimeter of the convex hull of the given points.
// The algorithm is Andrew's monotone chain.
// It is fully deterministic and has the same numerical behaviour as the original.
inline double convexHullPerimeter(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Work on a copy that will be sorted
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) {
        return a.x < b.x || (a.x == b.x && a.y < b.y);
    });

    std::vector<Point> hull;
    hull.reserve(2 * n);

    // Cross product to test turn direction
    auto cross = [](const Point& a, const Point& b, const Point& c) noexcept {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    };

    // Build lower hull
    for (const auto& p : pts) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull.back(), p) <= 0.0)
            hull.pop_back();
        hull.push_back(p);
    }

    // Build upper hull
    const std::size_t lowerSize = hull.size();
    for (auto it = pts.rbegin() + 1; it != pts.rend(); ++it) {
        const auto& p = *it;
        while (hull.size() > lowerSize &&
               cross(hull[hull.size() - 2], hull.back(), p) <= 0.0)
            hull.pop_back();
        hull.push_back(p);
    }

    // Last point is same as first, drop it
    if (!hull.empty())
        hull.pop_back();

    // Compute perimeter
    double perimeter = 0.0;
    for (std::size_t i = 0; i < hull.size(); ++i) {
        const std::size_t j = (i + 1) % hull.size();
        perimeter += dist(hull[i], hull[j]);
    }
    return perimeter;
}
