struct COOElement {
   size_t row, column;
   double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:

   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
void solveLinearSystem(std::vector<COOElement> const& A, std::vector<double> const& b, std::vector<double> &x, size_t N) {
   // Allocate a flattened dense matrix (row-major)
   std::vector<double> matrix(N * N, 0.0);

   // Fill the matrix with the values from A
   for (const auto& e : A) {
      if (e.row >= N || e.column >= N)
         throw std::out_of_range("COO indices out of bounds");
      matrix[e.row * N + e.column] = e.value;
   }

   // Make a copy of b to operate on
   std::vector<double> b_copy = b;
   if (b_copy.size() != N)
      throw std::invalid_argument("Vector size mismatch");

   x.assign(N, 0.0);

   // Forward elimination with partial pivoting
   for (size_t i = 0; i < N; ++i) {
      // Find pivot row
      size_t maxRow = i;
      double maxVal = std::abs(matrix[i * N + i]);

      #pragma omp parallel for reduction(max:maxVal)
      for (size_t r = i + 1; r < N; ++r) {
         double val = std::abs(matrix[r * N + i]);
         if (val > maxVal) {
            #pragma omp critical
            if (val > maxVal) {
               maxVal = val;
               maxRow = r;
            }
         }
      }

      if (maxVal < 1e-15) // singular or nearly singular matrix
         throw std::runtime_error("Matrix is singular or ill‑conditioned");

      // Swap current row with pivot row if needed
      if (maxRow != i) {
         for (size_t c = i; c < N; ++c) {
            std::swap(matrix[maxRow * N + c], matrix[i * N + c]);
         }
         std::swap(b_copy[maxRow], b_copy[i]);
      }

      double pivot = matrix[i * N + i];

      // Eliminate rows below i in parallel
      #pragma omp parallel for
      for (size_t r = i + 1; r < N; ++r) {
         double factor = matrix[r * N + i] / pivot;
         matrix[r * N + i] = 0.0; // Explicitly set to zero
         for (size_t c = i + 1; c < N; ++c) {
            matrix[r * N + c] -= factor * matrix[i * N + c];
         }
         b_copy[r] -= factor * b_copy[i];
      }
   }

   // Back substitution
   for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
      double sum = b_copy[i];
      for (size_t j = i + 1; j < N; ++j) {
         sum -= matrix[i * N + j] * x[j];
      }
      x[i] = sum / matrix[i * N + i];
   }
}
