#include <omp.h>

/*
 * Simulate one generation of Game of Life on `input`. Store the results in `output`.
 * Both `input` and `output` are NxN grids stored in row-major order.
 *
 * The implementation below uses OpenMP to parallelise the two nested loops.
 * Each iteration computes the neighbor sum with a handful of integer additions
 * and then applies the standard Game‑of‑Life rules. The code is carefully
 * written to avoid any bounds‑checking by the compiler and to keep all
 * pointer arithmetic local for maximum cache efficiency.
 */
void gameOfLife(std::vector<int> const& input, std::vector<int> &output, size_t N) {
    const int *in = input.data();
    int *out = output.data();
    const size_t stride = N;

    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const int *row_above  = (i > 0) ? in + (i - 1) * stride : nullptr;
        const int *row_below  = (i < N-1) ? in + (i + 1) * stride : nullptr;
        int *cur_out = out + i * stride;
        const int *cur_in = in + i * stride;

        for (size_t j = 0; j < N; ++j) {
            int sum = 0;

            /* vertical neighbors */
            if (row_above) sum += row_above[j];
            if (row_below) sum += row_below[j];

            /* horizontal neighbors */
            if (j > 0)     sum += cur_in[j-1];
            if (j < N-1)   sum += cur_in[j+1];

            /* diagonal neighbors */
            if (row_above && j > 0)     sum += row_above[j-1];
            if (row_above && j < N-1)   sum += row_above[j+1];
            if (row_below && j > 0)     sum += row_below[j-1];
            if (row_below && j < N-1)   sum += row_below[j+1];

            /* apply rules */
            int cur = cur_in[j];
            if (cur) {
                cur_out[j] = (sum == 2 || sum == 3) ? 1 : 0;
            } else {
                cur_out[j] = (sum == 3) ? 1 : 0;
            }
        }
    }
}
