/*
 * Return true if `val` is only in one of vectors x or y.
 * Return false if it is in both or neither.
 */
inline bool xorContains(const std::vector<int>& x, const std::vector<int>& y, int val)
{
    // iterate manually to avoid iterator overhead
    bool foundInX = false;
    for (const int* p = x.data(), *e = x.data() + x.size(); p != e; ++p)
        if (*p == val) { foundInX = true; break; }

    bool foundInY = false;
    if (!foundInX) {                     // early exit if already found in X
        for (const int* p = y.data(), *e = y.data() + y.size(); p != e; ++p)
            if (*p == val) { foundInY = true; break; }
        return true;                     // only in X
    }

    for (const int* p = y.data(), *e = y.data() + y.size(); p != e; ++p)
        if (*p == val) { foundInY = true; break; }

    return foundInX ^ foundInY;
}
