/* Compute the prefix sum of the vector x into output.
   Example:
   input: [1, 7, 4, 6, 6, 2]
   output: [1, 8, 12, 18, 24, 26]
*/
inline void prefixSum(std::vector<int64_t> const& x, std::vector<int64_t> &output) {
    std::size_t const n = x.size();
    output.resize(n);
    if (n == 0) return;

    int const numThreads = omp_get_max_threads();
    std::vector<int64_t> blockSums(numThreads, 0);

    // First pass: each thread computes a local inclusive scan and its local sum
    #pragma omp parallel
    {
        int const tid = omp_get_thread_num();
        std::size_t const chunk = (n + numThreads - 1) / numThreads;
        std::size_t const start = tid * chunk;
        std::size_t const end   = std::min(start + chunk, n);

        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum += x[i];
            output[i] = sum;
        }
        blockSums[tid] = sum;
    }

    // Compute offsets for each block
    int64_t offset = 0;
    for (int t = 0; t < numThreads; ++t) {
        int64_t const tmp = blockSums[t];
        blockSums[t] = offset;
        offset += tmp;
    }

    // Second pass: add the block offset to each element in the block
    #pragma omp parallel
    {
        int const tid   = omp_get_thread_num();
        std::size_t const chunk = (n + numThreads - 1) / numThreads;
        std::size_t const start = tid * chunk;
        std::size_t const end   = std::min(start + chunk, n);
        int64_t const add = blockSums[tid];

        for (std::size_t i = start; i < end; ++i) {
            output[i] += add;
        }
    }
}
