/*
 * Compute the rank (0‑based index in the sorted order) of each element in `x`
 * and write the results into `ranks_`.  The function preserves the exact
 * behaviour of the original implementation while targeting better
 * performance on x86‑64 with GCC.
 */
inline void ranks(std::vector<float> const& x, std::vector<std::size_t>& ranks_)
{
    const std::size_t n = x.size();
    ranks_.resize(n);

    /* Build an index array and sort it according to the corresponding
     * values in `x`.  The lambda captures only a raw pointer to the data
     * array so that the comparison is cache‑friendly. */
    std::vector<std::size_t> idx(n);
    std::iota(idx.begin(), idx.end(), 0);

    const float* data = x.data();   // raw pointer for fast access
    std::sort(idx.begin(), idx.end(),
              [data](std::size_t a, std::size_t b) noexcept {
                  return data[a] < data[b];
              });

    /* Write the ranks back to the output vector.  The loop is trivial
     * compared to the sort, so a serial loop is sufficient. */
    for (std::size_t i = 0; i < n; ++i)
        ranks_[idx[i]] = i;
}
