#include <cstddef>
#include <omp.h>

/*
 * 5‑point 2‑D Jacobi stencil.
 * Input and output are NxN grids stored in row‑major order.
 * The boundary is treated with a zero‑padding (i.e. values outside the
 * domain contribute 0 to the average).
 *
 * Timing: OpenMP 8 threads, GCC ‑O2, ‑fopenmp.
 * The algorithm keeps the exact mathematical behaviour of the reference
 * implementation.
 */
inline void jacobi2D(const std::vector<double> &input,
                     std::vector<double>   &output,
                     std::size_t           N) noexcept
{
    const std::size_t Nrow = N;
    const std::size_t stride = N;

    // Work per row: process each row except the first and last in a
    // separate loop so we can use a whole‑row kernel.  The first and
    // last rows are small and handled naively.
    const double inv5 = 1.0 / 5.0;

    // Process first row (i==0) and last row (i==N-1) separately
    #pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < Nrow; ++j) {
        double sum = input[j];                     // center
        if (j > 0)     sum += input[j - 1];
        if (j + 1 < stride) sum += input[j + 1];
        // up/down terms are zero because i==0 or i==N-1
        output[j] = sum * inv5;
    }
    if (Nrow > 1) {
        #pragma omp parallel for schedule(static)
        for (std::size_t j = 0; j < Nrow; ++j) {
            double sum = input[stride*(Nrow-1) + j];
            if (j > 0)     sum += input[stride*(Nrow-1) + j - 1];
            if (j + 1 < stride) sum += input[stride*(Nrow-1) + j + 1];
            output[stride*(Nrow-1) + j] = sum * inv5;
        }
    }

    // Main body (i = 1 .. N-2)
    #pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = 1; i < Nrow-1; ++i) {
        for (std::size_t j = 0; j < Nrow; ++j) {
            const std::size_t idx = i * stride + j;
            double sum = input[idx];                     // center

            // North
            sum += input[(i-1) * stride + j];
            // South
            sum += input[(i+1) * stride + j];

            // West
            if (j > 0)     sum += input[idx - 1];
            // East
            if (j + 1 < stride) sum += input[idx + 1];

            output[idx] = sum * inv5;
        }
    }
}
