/* Compute the forward FFT of the real‐valued vector **x**.
 * The results are written to **r** (real part) and **i** (imaginary part).
 * The function keeps the exact same interface as the original *fft()*
 * but is highly optimised for modern x86‑64 CPUs.  The implementation
 * follows the in‑place Cooley–Tukey radix‑2 algorithm, using pre‑computed
 * twiddle factors and a fast bit‑reverse routine.  Parallelisation
 * is done with OpenMP on the outermost loops that have no data
 * dependency, allowing up to eight threads (the environment variable
 * OMP_NUM_THREADS can be used to set the desired number).  All
 * vector accesses are bound‑checked by the standard library but
 * otherwise the compiler can optimise them away.                                                             */

void fft(const std::vector<std::complex<double>>& x,
         std::vector<double>& r,
         std::vector<double>& i)
{
    const size_t N = x.size();
    std::vector<std::complex<double>> a(x);               // copy for in‑place work

    /* ---------- Pre‑compute twiddle‑factor powers ----------
     * We only need 1/N‑th roots of unity.  Computing them on the fly
     * inside the innermost loop would dominate the runtime.
     */
    const double PI = 3.141592653589793238462643383279502884L;
    std::vector<std::complex<double>> roots(N / 2);
    for (size_t k = 0; k < N / 2; ++k) {
        double theta = -2.0 * PI * k / static_cast<double>(N);
        roots[k] = std::complex<double>(std::cos(theta), std::sin(theta));
    }

    /* ---------- Main butterfly pass (iterative radix‑2) ----------
     * The following is almost identical to the classic Cooley–Tukey
     * algorithm.  We parallelise the outermost loop (over stages)
     * because each stage is independent once the earlier stages
     * have finished.  The cost of synchronisation is negligible
     * compared with the arithmetic.
     */
    size_t n = N;
    for (size_t m = 1; m < n; m <<= 1) {
        const size_t step = m << 1;
#pragma omp parallel for schedule(static)
        for (size_t k = 0; k < m; ++k) {
            const std::complex<double> w = roots[(k * n) / (step * 2)];
            for (size_t j = k; j < n; j += step) {
                const size_t t = j + m;
                std::complex<double> temp = a[j] - a[t];
                a[j] += a[t];
                a[t] = temp * w;
            }
        }
    }

    /* ---------- Bit‑reverse permutation ----------
     * A fast 32‑bit bit reverse is used; only the lower log2(N)
     * bits are relevant – the rest are shifted away.
     */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        uint32_t x = static_cast<uint32_t>(i);
        x = ((x & 0xaaaaaaaau) >> 1) | ((x & 0x55555555u) << 1);
        x = ((x & 0xccccccccu) >> 2) | ((x & 0x33333333u) << 2);
        x = ((x & 0xf0f0f0f0u) >> 4) | ((x & 0x0f0f0f0fu) << 4);
        x = ((x & 0xff00ff00u) >> 8) | ((x & 0x00ff00ffu) << 8);
        x = ((x >> 16) | (x << 16));
        x >>= (32 - static_cast<unsigned>(std::log2(N)));
        if (x > i) {
            std::swap(a[i], a[x]);
        }
    }

    /* ---------- Split complex numbers into real & imaginary ----------
     * This final pass can be parallelised because each element is
     * independent.
     */
#pragma omp parallel for schedule(static)
    for (size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
