/*=============================================
    Optimised convex hull (Monotone chain)
  ============================================*/

struct Point {
    double x, y;
};

/*  Cross product of AB × AC  */
inline double cross(const Point& a, const Point& b, const Point& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/*  The implementation conforms exactly to the original behaviour  */
inline void convexHull(std::vector<Point> const& points, std::vector<Point> &hull)
{
    const size_t n = points.size();
    if (n < 3) {
        hull = points;               // copy, preserves order
        return;
    }

    // -------- 1. Sort points by (x, y)  ---------------------------------
    std::vector<Point> pts = points;  // copy once, no further allocations
    // Use parallel sort if the compiler/runtime supports it
    #if defined(_GLIBCXX_PARALLEL) && defined(_GLIBCXX_PARALLEL_MODE)
        std::sort(std::execution::par, pts.begin(), pts.end(),
                  [](const Point& a, const Point& b) {
                      return (a.x < b.x) || (a.x == b.x && a.y < b.y);
                  });
    #else
        std::sort(pts.begin(), pts.end(),
                  [](const Point& a, const Point& b) {
                      return (a.x < b.x) || (a.x == b.x && a.y < b.y);
                  });
    #endif

    // -------- 2. Build lower hull ---------------------------------------
    hull.clear();
    hull.reserve(n);   // maximum possible size

    for (size_t i = 0; i < n; ++i) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size()-2], hull[hull.size()-1], pts[i]) <= 0.0)
            hull.pop_back();
        hull.push_back(pts[i]);
    }

    // -------- 3. Build upper hull ---------------------------------------
    const size_t lower_size = hull.size();
    for (size_t i = n-1; i-- > 0; /* nothing */) {
        while (hull.size() > lower_size + 1 &&
               cross(hull[hull.size()-2], hull[hull.size()-1], pts[i]) <= 0.0)
            hull.pop_back();
        hull.push_back(pts[i]);
    }

    // The last point is the same as the first one; remove duplicate edge
    hull.pop_back();
}
