#include <cstddef>
#include <omp.h>

/* Optimised matrix multiplication.
 * A is MxK, B is KxN, C is MxN (row‑major).
 * Uses a cache‑friendly blocked algorithm with OpenMP parallelism.
 * The interface is kept identical to the original routine. */
inline void gemm(const std::vector<double>& A,
                 const std::vector<double>& B,
                 std::vector<double>& C,
                 size_t M, size_t K, size_t N)
{
    /* Tile sizes chosen to fit in L1/L2 cache.
     * Can be tuned to the specific hardware.          */
    constexpr size_t TILE_M = 64;
    constexpr size_t TILE_K = 64;
    constexpr size_t TILE_N = 64;

    /* Initialise C to zero if it has not been set. */
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < M * N; ++idx)
        C[idx] = 0.0;

    /* Parallelise over chunks of the M‑dimension. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i0 = 0; i0 < M; i0 += TILE_M) {
        for (size_t j0 = 0; j0 < N; j0 += TILE_N) {
            /* Iterate over K in tiles. */
            for (size_t k0 = 0; k0 < K; k0 += TILE_K) {
                /* Compute the block C[i0..i0+TILE_M-1][j0..j0+TILE_N-1] */
                for (size_t i = i0; i < std::min(i0 + TILE_M, M); ++i) {
                    const size_t a_row = i * K;
                    const size_t c_row = i * N;
                    for (size_t k = k0; k < std::min(k0 + TILE_K, K); ++k) {
                        const double a_val = A[a_row + k];
                        const size_t b_col_base = k * N;
                        /* Inner loop over N, unrolled by 4 for extra speed. */
                        size_t j = j0;
                        for (; j + 3 < std::min(j0 + TILE_N, N); j += 4) {
                            C[c_row + j    ] += a_val * B[b_col_base + j];
                            C[c_row + j + 1] += a_val * B[b_col_base + j + 1];
                            C[c_row + j + 2] += a_val * B[b_col_base + j + 2];
                            C[c_row + j + 3] += a_val * B[b_col_base + j + 3];
                        }
                        /* Handle remaining elements */
                        for (; j < std::min(j0 + TILE_N, N); ++j) {
                            C[c_row + j] += a_val * B[b_col_base + j];
                        }
                    }
                }
            }
        }
    }
}
