#pragma once
#include <vector>
#include <cmath>
#include <complex>
#include <algorithm>
#include <numeric>
#include <omp.h>

#ifndef M_PI
#define M_PI 3.141592653589793238462643383279502884L
#endif

// -----------------------------------------------------
//  In‑place iterative Cooley‑Tukey radix‑2 FFT with
//  OpenMP parallelism and bit‑reversal permutation.
// -----------------------------------------------------
void fft(const std::vector<std::complex<double>> &x,
         std::vector<std::complex<double>> &output)
{
    unsigned int N = static_cast<unsigned int>(x.size());
    if (N == 0) { output.clear(); return; }

    // Ensure N is power of two
    if ( (N & (N - 1)) != 0 ) {
        throw std::runtime_error("fft: input size must be power of two");
    }

    output = x;                     // work array

    // Pre‑compute bit‑reversal indices
    unsigned int m = static_cast<unsigned int>(std::log2(N));
    std::vector<unsigned int> rev(N);
    for (unsigned int i = 0; i < N; ++i)
    {
        unsigned int r = i;
        r = ((r & 0x55555555u) << 1) | ((r & 0xaaaaaaaau) >> 1);
        r = ((r & 0x33333333u) << 2) | ((r & 0xccccccccu) >> 2);
        r = ((r & 0x0f0f0f0fu) << 4) | ((r & 0xf0f0f0f0u) >> 4);
        r = ((r & 0x00ff00ffu) << 8) | ((r & 0xff00ff00u) >> 8);
        r = (r << 16) | (r >> 16);
        rev[i] = r >> (32 - m);
    }

    // Bit‑reversal permutation
    for (unsigned int i = 0; i < N; ++i)
    {
        unsigned int j = rev[i];
        if (j > i) std::swap(output[i], output[j]);
    }

    // Pre‑compute twiddle factors for each stage
    std::vector<std::vector<std::complex<double>>> twiddles(m);
    for (unsigned int s = 0; s < m; ++s)
    {
        unsigned int span = 1u << s;      // half‑size of sub‑FFT
        unsigned int full  = span << 1;   // size of sub‑FFT
        twiddles[s].resize(span);
        double angle = -M_PI / span;
        for (unsigned int k = 0; k < span; ++k)
        {
            double w_re = std::cos(k * angle);
            double w_im = std::sin(k * angle);
            twiddles[s][k] = std::complex<double>(w_re, w_im);
        }
    }

    // Butterfly stages
    for (unsigned int s = 0; s < m; ++s)
    {
        unsigned int span = 1u << s;      // half‑size
        unsigned int full  = span << 1;   // size of sub‑FFT
        const auto &ws = twiddles[s];

#pragma omp parallel for schedule(static)
        for (unsigned int i = 0; i < N; i += full)
        {
            for (unsigned int j = 0; j < span; ++j)
            {
                std::complex<double> t = ws[j] * output[i + j + span];
                std::complex<double> u = output[i + j];
                output[i + j]         = u + t;
                output[i + j + span]   = u - t;
            }
        }
    }
}
