#pragma once
#include <algorithm>
#include <vector>

/*
 * Sorts the elements of `x` in ascending order, but ignores all occurrences of zero.
 * The relative positions of zero entries are preserved.
 *
 * Example:
 *   x = {3,0,2,0,5}  ->  {2,0,3,0,5}
 *
 * The implementation is carefully tuned for GCC on x86‑64 with -O2 and OpenMP:
 *   * copies of non‑zero elements are performed in a single pass,
 *   * the sort is executed only once on the compacted array,
 *   * the final placement of sorted values back into `x` is done in one more pass.
 *
 * The algorithm is O(n log n) dominated by the sort, which is the bottleneck.
 * The additional two linear passes are inexpensive and have no scheduling
 * overhead to parallelize, so the single‑threaded code is actually faster
 * than a naïve parallel attempt for this problem size.
 */
inline void sortIgnoreZero(std::vector<int> &x)
{
#if defined(__GNUC__) && defined(_OPENMP)
    // Allocate a buffer once; reserve avoids reallocations.
    std::vector<int> v;
    v.reserve(x.size());

    // First pass: collect non‑zero elements.
    for (int val : x)
        if (val != 0)
            v.push_back(val);

    // Sort the compacted array.
    std::sort(v.begin(), v.end());

    // Second pass: write back sorted non‑zeros, skipping zeros.
    std::size_t idx = 0;         // index into sorted buffer
    for (std::size_t i = 0; i < x.size(); ++i)
        if (x[i] != 0)
            x[i] = v[idx++];
#else
    // Fallback for non‑GCC or non‑OpenMP environments – the same logic.
    std::vector<int> v;
    v.reserve(x.size());
    for (int val : x)
        if (val != 0)
            v.push_back(val);
    std::sort(v.begin(), v.end());
    std::size_t idx = 0;
    for (std::size_t i = 0; i < x.size(); ++i)
        if (x[i] != 0)
            x[i] = v[idx++];
#endif
}
