13_geometry_closest_pair_2d:
```cpp
#pragma once
#include <vector>
#include <limits>
#include <algorithm>
#include <cmath>

struct Point {
    double x, y;
};

/* Compute the minimal Euclidean distance between two points
   using a faster implementation that only takes the square root
   once for the final result. */
static inline double squaredDist(const Point& a, const Point& b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

/* The recursive routine works on points sorted by x coordinate
   and additionally keeps a buffer sorted by y coordinate
   for the strip construction. */
static double closestRec(
    std::vector<Point> const& px,
    size_t l, size_t r,
    std::vector<Point>& py,   // buffer sorted by y
    std::vector<Point>& temp) // scratch buffer
{
    size_t n = r - l;
    if (n <= 3) {
        double best = std::numeric_limits<double>::max();
        for (size_t i = l; i < r; ++i)
            for (size_t j = i + 1; j < r; ++j) {
                double d = squaredDist(px[i], px[j]);
                if (d < best) best = d;
            }
        std::sort(px.begin() + l, px.begin() + r,
                  [](const Point& a, const Point& b){ return a.y < b.y; });
        return best;
    }

    size_t mid = l + n / 2;
    double midx = px[mid].x;

    // divide
    std::vector<Point> pyLeft, pyRight;
    pyLeft.reserve((mid - l));
    pyRight.reserve((r - mid));
    for (size_t i = l; i < r; ++i) {
        if (px[i].x <= midx) pyLeft.push_back(px[i]); 
        else pyRight.push_back(px[i]);
    }

    double dl = closestRec(px, l, mid, pyLeft, temp);
    double dr = closestRec(px, mid, r, pyRight, temp);
    double dbest = dl < dr ? dl : dr;

    // merge pyLeft and pyRight into py (sorted by y)
    py.clear();
    py.reserve(n);
    size_t i = 0, j = 0;
    while (i < pyLeft.size() && j < pyRight.size()) {
        if (pyLeft[i].y < pyRight[j].y) py.push_back(pyLeft[i++]);
        else py.push_back(pyRight[j++]);
    }
    while (i < pyLeft.size()) py.push_back(pyLeft[i++]);
    while (j < pyRight.size()) py.push_back(pyRight[j++]);

    // build strip
    temp.clear();
    for (const Point& p : py) {
        if ( (p.x - midx) * (p.x - midx) < dbest )
            temp.push_back(p);
    }

    // compare each point in the strip with next up to 7 points
    for (size_t a = 0; a < temp.size(); ++a) {
        for (size_t b = a + 1; b < temp.size() && (temp[b].y - temp[a].y) * (temp[b].y - temp[a].y) < dbest; ++b) {
            double d = squaredDist(temp[a], temp[b]);
            if (d < dbest) dbest = d;
        }
    }

    return dbest;
}

/* Public API – closest pair distance */
double closestPair(std::vector<Point> const& points) {
    size_t n = points.size();
    if (n < 2) return 0.0;

    // Sort points by x coordinate once
    std::vector<Point> px = points;
    std::sort(px.begin(), px.end(),
              [](const Point& a, const Point& b){ return a.x < b.x; });

    std::vector<Point> py, temp;
    py.reserve(n);
    temp.reserve(n);

    double d2 = closestRec(px, 0, n, py, temp);
    return std::sqrt(d2);
}
