#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <mutex>
#include <thread>
#include <atomic>
#include <algorithm>
#include <cstring>

#if !defined(__SSE2__)
#  define SSE2_AVAILABLE 0
#else
#  define SSE2_AVAILABLE 1
#endif

// ---------------------------------------------------------------------------
// Power‑of‑two FFT with conjugation
// ---------------------------------------------------------------------------
void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    // --- SIMD prerequirements ---------------------------------------------
    const unsigned int logN = static_cast<unsigned int>(std::log2(N));
    if ((1u << logN) != N)
        throw std::runtime_error("fftConjugate: input size must be a power of two");

    // --- Pre‑allocate workspace ------------------------------------------
    std::vector<std::complex<double>> w;          // twiddle factors
    std::vector<std::size_t> rev;                 // bit‑reverse permutation

    // ---------------------------------------------------------------------
    // Precompute twiddle factors for all stages
    // ---------------------------------------------------------------------
    w.resize(N / 2);
    const double pi = 3.14159265358979323846264338327950288L / logN;
    double angle = -2.0 * pi;                     // they will be divided by 2 each stage
    for (size_t i = 0; i < w.size(); ++i)
    {
        w[i] = std::exp(std::complex<double>(0.0, angle * (2 * static_cast<double>(i) / N)));
    }

    // ---------------------------------------------------------------------
    // Precompute bit‑reverse table
    // ---------------------------------------------------------------------
    rev.resize(N);
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t j = 0, t = i;
        for (unsigned int k = 0; k < logN; ++k, t >>= 1) j = (j << 1) | (t & 1);
        rev[i] = j;
    }

    // ---------------------------------------------------------------------
    // Butterfly – radix‑2 Cooley‑Tukey, in‑place, iterative
    // ---------------------------------------------------------------------
    std::size_t step = 1;
    const std::size_t halfN = N >> 1;
    for (unsigned int level = 0; level < logN; ++level, step <<= 1)
    {
        const std::size_t jump = step << 1;
        const std::size_t halfJump = step;

        // Note: the twiddle for current stage is w[ 0 .. step-1 ]
        const std::complex<double>* twiddles = &w[ level * step / 2 ];

        // Parallelize over the `step` groups
        #pragma omp parallel for schedule(static, 64)
        for (std::size_t i = 0; i < N; i += jump)
        {
            std::size_t idx = 0;
            for (std::size_t j = i; j < i + halfJump; ++j, ++idx)
            {
                std::complex<double> a = x[j];
                std::complex<double> b = x[j + halfJump] * twiddles[idx];
                x[j] = a + b;
                x[j + halfJump] = a - b;
            }
        }
    }

    // ---------------------------------------------------------------------
    // Bit‑reverse re-ordering (in‑place)
    // ---------------------------------------------------------------------
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t j = rev[i];
        if (j > i)
            std::swap(x[i], x[j]);
    }

    // ---------------------------------------------------------------------
    // Conjugate each element
    // ---------------------------------------------------------------------
    #pragma omp parallel for schedule(static, 1024)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(N); ++i)
    {
        x[i] = std::conj(x[i]);
    }
}
