#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <cstddef>
#include <omp.h>

/* Return the index of the value in the vector x that is closest to the math
   constant PI.  Use M_PI for the value of PI.
   Example:
   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
   output: 1
   The function is thread‑safe, built for GCC –O2 with OpenMP support, and
   consumes no additional memory beyond the input vector. */
inline
size_t findClosestToPi(const std::vector<double>& x)
{
    // The library code assumes that x.size() > 0.  We keep that contract.
    const size_t n = x.size();

    /* If the input is small, the overhead of multithreading outweighs its
       benefit.  Threshold is empirically chosen to be 4k elements. */
    if (n < 4096) {
        size_t index = 0;
        double min_diff = std::abs(x[0] - M_PI);
        for (size_t i = 1; i < n; ++i) {
            double d = std::abs(x[i] - M_PI);
            if (d < min_diff) {
                min_diff = d;
                index = i;
            }
        }
        return index;
    }

    /* Parallel scan: each thread keeps a local best value/index.
       After the loop the global best is computed. */
    struct Best {
        double diff;
        size_t idx;
    };

    std::vector<Best> local_best(omp_get_max_threads());
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        size_t start = tid * n / omp_get_num_threads();
        size_t end   = (tid + 1) * n / omp_get_num_threads();

        // initialise local best
        local_best[tid].diff = std::numeric_limits<double>::infinity();
        local_best[tid].idx  = 0;

        for (size_t i = start; i < end; ++i) {
            double d = std::abs(x[i] - M_PI);
            if (d < local_best[tid].diff) {
                local_best[tid].diff = d;
                local_best[tid].idx  = i;
            }
        }
    }

    // reduce across threads
    size_t best_idx = 0;
    double best_diff = std::numeric_limits<double>::infinity();
    for (const auto& b : local_best) {
        if (b.diff < best_diff) {
            best_diff = b.diff;
            best_idx  = b.idx;
        }
    }
    return best_idx;
}
