```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <cstdint>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.141592653589793238462643383279502884L
#endif

// ---------------------------------------------------------
//  Iterative radix‑2 Cooley‑Tukey FFT with in‑place bit reversal
// ---------------------------------------------------------

namespace detail
{
    // Pre‑computed sin/cos tables for each stage (N must be power of 2)
    struct fft_stage
    {
        std::vector<std::complex<double>> twiddles;
        std::size_t stride;
    };

    // Build stages for a given size N
    static std::vector<fft_stage> build_stages(std::size_t N)
    {
        std::vector<fft_stage> stages;
        std::size_t n = N;
        while (n > 1)
        {
            n >>= 1;
            fft_stage st;
            st.stride = n;
            st.twiddles.resize(n);
            double angle_step = -2.0 * M_PI / n;
            for (std::size_t k = 0; k < n; ++k)
                st.twiddles[k] = std::polar(1.0, angle_step * k);
            stages.push_back(std::move(st));
        }
        return stages;
    }

    // Bit reversal swap using 32‑bit method (N <= 2^32)
    static inline std::size_t bit_reverse(std::size_t x, std::size_t log2N)
    {
        x = ((x & 0xaaaaaaaaaaaaaaaaULL) >> 1)  | ((x & 0x5555555555555555ULL) << 1);
        x = ((x & 0xccccccccccccccccULL) >> 2)  | ((x & 0x3333333333333333ULL) << 2);
        x = ((x & 0xf0f0f0f0f0f0f0f0ULL) >> 4)  | ((x & 0x0f0f0f0f0f0f0f0fULL) << 4);
        x = ((x & 0xff00ff00ff00ff00ULL) >> 8)  | ((x & 0x00ff00ff00ff00ffULL) << 8);
        x = ((x & 0xffff0000ffff0000ULL) >>16)  | ((x & 0x0000ffff0000ffffULL) <<16);
        x =  (x >> (64 - log2N));
        return x;
    }

    // In‑place FFT
    template <typename iter>
    void fft_inplace(iter first, std::size_t N, const std::vector<fft_stage>& stages, bool reversed = false)
    {
        // Bit reverse permutation
        std::size_t log2N = static_cast<std::size_t>(std::log2(N));
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; ++i)
        {
            std::size_t j = bit_reverse(i, log2N);
            if (j > i)
            {
                std::swap(*(first + i), *(first + j));
            }
        }

        // Butterfly stages
        for (std::size_t stage = 0; stage < stages.size(); ++stage)
        {
            const auto& st = stages[stage];
            std::size_t stride = st.stride;

            #pragma omp parallel for schedule(static)
            for (std::size_t block = 0; block < N; block += 2 * stride)
            {
                for (std::size_t k = 0; k < stride; ++k)
                {
                    std::size_t i = block + k;
                    std::size_t j = i + stride;
                    std::complex<double> t = (*first)[i] - (*first)[j];
                    (*first)[i] += (*first)[j];
                    (*first)[j] = t * (reversed ? std::conj(st.twiddles[k]) : st.twiddles[k]);
                }
            }
        }
    }
}

// ---------------------------------------------------------
//  Public API (assumes N is a power of two)
// ---------------------------------------------------------

void fft_helper(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    static std::vector<detail::fft_stage> stages = detail::build_stages(N);
    detail::fft_inplace(&x[0], N, stages, /*reversed=*/false);
}

void ifft(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    // Conjugate input
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);

    // Forward FFT
    fft_helper(x);

    // Conjugate again
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);

    // Scale by 1/N
    double invN = 1.0 / static_cast<double>(N);
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] *= invN;
}
